<?php
namespace App\Domain\Characters\Appearance;
use App\Domain\Inventory\Instances\ItemInstanceStatus;use App\Domain\Media\CharacterVisuals\CharacterVisualAssetService;use App\Domain\Media\MediaAssetType;use App\Models\Character;use Illuminate\Support\Facades\Storage;use Throwable;
final class CharacterAppearanceService{private $base;private $slots;public function __construct(CharacterVisualAssetService $base,ItemVisualSlotResolver $slots){$this->base=$base;$this->slots=$slots;}public function presentation(Character $character){$character->loadMissing(['characterTemplate.mediaAssets','equipment.itemInstance.item.visualAssets.mediaAsset']);$template=$character->characterTemplate;$bodyType=$template&&is_string($template->body_type)&&$template->body_type!==''?$template->body_type:null;$base=$this->base->presentation($template);$layers=[];if($bodyType){foreach($character->equipment as$row){$instance=$row->itemInstance;$item=$instance?$instance->item:null;if(!$instance||!$item||(int)$row->character_id!==(int)$character->id||(int)$instance->character_id!==(int)$character->id||$instance->status!==ItemInstanceStatus::EQUIPPED)continue;$visualSlot=$this->slots->visualSlotForEquipmentSlot($row->slot);try{$this->slots->assertAllowed($item,$visualSlot);}catch(Throwable $e){continue;}$link=$item->visualAssets->first(function($candidate)use($bodyType,$visualSlot){return$candidate->body_type===$bodyType&&$candidate->visual_slot===$visualSlot;});$asset=$link?$link->mediaAsset:null;if(!$asset||$asset->asset_type!==MediaAssetType::EQUIPMENT_LAYER||!Storage::disk($asset->disk)->exists($asset->path))continue;$layers[]=['equipment_slot'=>$row->slot,'visual_slot'=>$visualSlot,'order'=>CharacterVisualLayerOrder::orderForSlot($visualSlot),'item_id'=>(int)$item->id,'item_name'=>$item->name,'body_type'=>$bodyType,'url'=>$asset->url(),'media_asset_id'=>(int)$asset->id];}}usort($layers,function($a,$b){return$a['order']<=>$b['order'];});return['canvas'=>['width'=>512,'height'=>768],'base_body'=>['visual_slot'=>'base_body','order'=>10,'url'=>$base->url256()],'layers'=>$layers,'body_type'=>$bodyType,'fallback_used'=>!$base->exists()];}}
